import React from 'react';
import { Calendar } from 'lucide-react';
import SectionTitle from '../common/SectionTitle';

const Incoming = ({ id }) => {
  const opportunities = [
    {
      title: "AWS Cloud Solutions Architect and Gen AI Intern",
      company: "Elevance Health - Atlanta GA",
      startDate: "Starting May 2025",
      description: "I'm excited to announce that I'll be joining Google's AI team as a Machine Learning Engineer, where I'll be working on next-generation voice synthesis technologies.",
      responsibilities: [
        "Will be developing advanced ML models for speech recognition and synthesis",
        "Collaborating with research scientists to implement cutting-edge AI techniques",
        "Contributing to open-source machine learning frameworks"
      ]
    },
    {
      title: "Returning Gen AI Innovation Intern!",
      company: "Southern Company - Atlanta, GA",
      startDate: "Coming August 2025",
      description: "I'll be participating in a prestigious research fellowship at Stanford's AI Lab, focusing on advancing state-of-the-art natural language processing models.",
      responsibilities: [
        "Conducting research on improving transformer architectures for multilingual NLP applications",
        "Working alongside Stanford faculty and PhD candidates",
        "Opportunity to publish findings in top-tier AI conferences"
      ]
    }
  ];

  return (
    <section id={id} className="py-16 bg-gray-50 dark:bg-gray-900 transition-colors duration-200">
      <div className="container mx-auto px-4">
        <SectionTitle title="Upcoming Opportunities" />
        <div className="max-w-3xl mx-auto">
          {opportunities.map((opportunity, index) => (
            <OpportunityCard 
              key={index} 
              opportunity={opportunity} 
              className={index < opportunities.length - 1 ? "mb-6" : ""}
            />
          ))}
        </div>
      </div>
    </section>
  );
};

const OpportunityCard = ({ opportunity, className = "" }) => {
  const { title, company, startDate, description, responsibilities } = opportunity;
  
  return (
    <div className={`bg-white dark:bg-gray-800 p-6 rounded-lg shadow-sm ${className}`}>
      <div className="flex items-center mb-4">
        <Calendar size={24} className="text-blue-600 dark:text-blue-400 mr-3" />
        <h3 className="text-xl font-semibold">{title}</h3>
      </div>
      <p className="text-blue-600 dark:text-blue-400 font-semibold mb-2">{company}</p>
      <p className="text-gray-600 dark:text-gray-400 mb-4">{startDate}</p>
      <div className="bg-blue-50 dark:bg-blue-900/20 p-4 rounded-lg">
        <p className="text-gray-700 dark:text-gray-300 mb-3">
          {description}
        </p>
        <ul className="list-disc pl-5 space-y-2 text-gray-700 dark:text-gray-300">
          {responsibilities.map((responsibility, index) => (
            <li key={index}>{responsibility}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default Incoming;