import React from 'react';
import { Mail, Phone } from 'lucide-react';
import SectionTitle from '../common/SectionTitle';

const Contact = ({ id }) => {
  const contactInfo = [
    {
      type: "Email",
      value: "kshrivastava33@gatech.edu",
      icon: <Mail size={24} className="text-blue-600 dark:text-blue-400 mr-4" />,
      href: "mailto:kshrivastava33@gatech.edu"
    },
    {
      type: "Phone",
      value: "(770) 710-5235",
      icon: <Phone size={24} className="text-blue-600 dark:text-blue-400 mr-4" />,
      href: "tel:+17707105235"
    },
    {
      type: "LinkedIn",
      value: "linkedin.com/in/kswork/",
      icon: (
        <div className="text-blue-600 dark:text-blue-400 mr-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 24 24">
            <path d="M19 3a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h14m-.5 15.5v-5.3a3.26 3.26 0 0 0-3.26-3.26c-.85 0-1.84.52-2.32 1.3v-1.11h-2.79v8.37h2.79v-4.93c0-.77.62-1.4 1.39-1.4a1.4 1.4 0 0 1 1.4 1.4v4.93h2.79M6.88 8.56a1.68 1.68 0 0 0 1.68-1.68c0-.93-.75-1.69-1.68-1.69a1.69 1.69 0 0 0-1.69 1.69c0 .93.76 1.68 1.69 1.68m1.39 9.94v-8.37H5.5v8.37h2.77z"/>
          </svg>
        </div>
      ),
      href: "https://linkedin.com/in/kswork/"
    },
    {
      type: "GitHub",
      value: "github.com/KSWORK2001",
      icon: (
        <div className="text-blue-600 dark:text-blue-400 mr-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 24 24">
            <path d="M12 2A10 10 0 0 0 2 12c0 4.42 2.87 8.17 6.84 9.5.5.08.66-.23.66-.5v-1.69c-2.77.6-3.36-1.34-3.36-1.34-.46-1.16-1.11-1.47-1.11-1.47-.91-.62.07-.6.07-.6 1 .07 1.53 1.03 1.53 1.03.87 1.52 2.34 1.07 2.91.83.09-.65.35-1.09.63-1.34-2.22-.25-4.55-1.11-4.55-4.92 0-1.11.38-2 1.03-2.71-.1-.25-.45-1.29.1-2.64 0 0 .84-.27 2.75 1.02.79-.22 1.65-.33 2.5-.33.85 0 1.71.11 2.5.33 1.91-1.29 2.75-1.02 2.75-1.02.55 1.35.2 2.39.1 2.64.65.71 1.03 1.6 1.03 2.71 0 3.82-2.34 4.66-4.57 4.91.36.31.69.92.69 1.85V21c0 .27.16.59.67.5C19.14 20.16 22 16.42 22 12A10 10 0 0 0 12 2z"/>
          </svg>
        </div>
      ),
      href: "https://github.com/KSWORK2001"
    }
  ];

  return (
    <section id={id} className="py-16 bg-white dark:bg-gray-800 transition-colors duration-200">
      <div className="container mx-auto px-4">
        <SectionTitle title="How about a Coffee Chat?" />
        <div className="max-w-2xl mx-auto bg-gray-50 dark:bg-gray-700 p-8 rounded-lg shadow-sm">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            {contactInfo.map((item, index) => (
              <ContactCard key={index} contact={item} />
            ))}
          </div>
          
          <div className="text-center">
            <p className="text-lg mb-4 dark:text-gray-300">
              Interested in working together? Feel free to reach out!
            </p>
            <a 
              href="mailto:kshrivastava33@gatech.edu" 
              className="inline-block bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors"
            >
              Send Message
            </a>
          </div>
        </div>
      </div>
    </section>
  );
};

const ContactCard = ({ contact }) => {
  const { type, value, icon, href } = contact;
  
  return (
    <a 
      href={href}
      className="flex items-center p-4 bg-blue-50 dark:bg-blue-900/20 rounded-lg hover:bg-blue-100 dark:hover:bg-blue-800/30 transition-colors"
    >
      {icon}
      <div>
        <h3 className="font-semibold mb-1 dark:text-gray-200">{type}</h3>
        <p className="text-gray-600 dark:text-gray-400">{value}</p>
      </div>
    </a>
  );
};

export default Contact;