import React from 'react';

const Footer = () => {
  return (
    <footer className="py-8 bg-gray-800 dark:bg-gray-900 text-white transition-colors duration-200">
      <div className="container mx-auto px-4 text-center">
        <p>&copy; {new Date().getFullYear()} Made with React, TailwindCSS, and NodeJS by yours truly :)</p>
      </div>
    </footer>
  );
};

export default Footer;