import React from 'react';
import { motion } from 'framer-motion';
import Typewriter from 'typewriter-effect';
import headshot from '../../headshot.jpg';

const Hero = ({ id }) => {
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
        duration: 0.8,
        when: 'beforeChildren',
      },
    },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6 } },
  };

  return (
    <section
      id={id}
      className="relative min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-500 via-indigo-600 to-purple-700 dark:from-blue-800 dark:via-indigo-800 dark:to-purple-900 text-white transition-colors duration-200 px-6 overflow-hidden"
      >

      <div className="absolute inset-0 -z-10 overflow-hidden">
          <div className="absolute w-72 h-72 bg-purple-400/20 rounded-full blur-3xl animate-float top-10 left-10" />
          <div className="absolute w-96 h-96 bg-blue-400/30 rounded-full blur-3xl animate-float delay-1000 bottom-0 right-10" />
          <div className="absolute w-60 h-60 bg-pink-400/20 rounded-full blur-2xl animate-float delay-2000 top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2" />
      </div>
      <motion.div
        className="max-w-4xl w-full flex flex-col items-center text-center space-y-8"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <motion.div
          className="w-52 h-52 md:w-64 md:h-64 rounded-full overflow-hidden border-4 border-white dark:border-gray-700 shadow-xl"
          variants={fadeUp}
        >
          <img
            src={headshot}
            alt="Karan Shrivastava"
            className="w-full h-full object-cover"
          />
        </motion.div>

        <motion.h1
          className="text-4xl md:text-6xl font-extrabold bg-clip-text text-transparent animated-gradient-text"
          variants={fadeUp}
        >
          Karan Shrivastava
        </motion.h1>

        <motion.div className="text-lg md:text-2xl text-white/90 max-w-xl h-12 flex justify-center" variants={fadeUp}>
          <Typewriter
            options={{loop: true, delay: 50, deleteSpeed: 30, html: true}}
            onInit={(typewriter) => {
              const open = `<span class='highlight'>`;
              const close = '</span>';
              typewriter
                .typeString(`I am a <span class='highlight'>Machine Learning Engineer!</span>`)
                .pauseFor(1000)
                .deleteChars(26)
                .typeString(`<span class='highlight'>Cloud Solutions Architect!</span>`)
                .pauseFor(1000)
                .deleteChars(26)
                .typeString(`<span class='highlight'>Grad Student at Georgia Tech!</span>`)
                .pauseFor(1000)
                .deleteChars(29)
                .typeString(`<span class='highlight'>Full Stack Software Engineer!</span>`)
                .pauseFor(1500)
                .deleteAll()
                .start();
            }}
          />
        </motion.div>

        <motion.div
          className="flex flex-wrap justify-center gap-4 mt-4"
          variants={fadeUp}
        >
          <a
            href="#projects"
            className="px-6 py-3 text-sm font-semibold bg-white text-blue-600 rounded-full hover:bg-blue-50 transition glow"
          >
            View Projects
          </a>
          <a
            href="/resume.pdf"
            download="Karan_Shrivastava_Resume.pdf"
            className="px-6 py-3 text-sm font-semibold border border-white text-white rounded-full hover:bg-white hover:text-blue-700 transition glow"
          >
            Download Resume
          </a>
        </motion.div>
        <motion.div
          className="flex gap-6 mt-6"
          variants={fadeUp}
        >
          {/* LinkedIn */}
          <a
            href="https://linkedin.com/in/kswork"
            target="_blank"
            rel="noopener noreferrer"
            className="hover:scale-110 transition-transform"
            aria-label="LinkedIn"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" className="w-6 h-6 text-white/80 hover:text-white" viewBox="0 0 24 24">
              <path d="M19 3a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h14m-.5 15.5v-5.3a3.26 3.26 0 0 0-3.26-3.26c-.85 0-1.84.52-2.32 1.3v-1.11h-2.79v8.37h2.79v-4.93c0-.77.62-1.4 1.39-1.4a1.4 1.4 0 0 1 1.4 1.4v4.93h2.79M6.88 8.56a1.68 1.68 0 0 0 1.68-1.68c0-.93-.75-1.69-1.68-1.69a1.69 1.69 0 0 0-1.69 1.69c0 .93.76 1.68 1.69 1.68m1.39 9.94v-8.37H5.5v8.37h2.77z"/>
            </svg>
          </a>

          {/* GitHub */}
          <a
            href="https://github.com/KSWORK2001"
            target="_blank"
            rel="noopener noreferrer"
            className="hover:scale-110 transition-transform"
            aria-label="GitHub"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" className="w-6 h-6 text-white/80 hover:text-white" viewBox="0 0 24 24">
              <path d="M12 2A10 10 0 0 0 2 12c0 4.42 2.87 8.17 6.84 9.5.5.08.66-.23.66-.5v-1.69c-2.77.6-3.36-1.34-3.36-1.34-.46-1.16-1.11-1.47-1.11-1.47-.91-.62.07-.6.07-.6 1 .07 1.53 1.03 1.53 1.03.87 1.52 2.34 1.07 2.91.83.09-.65.35-1.09.63-1.34-2.22-.25-4.55-1.11-4.55-4.92 0-1.11.38-2 1.03-2.71-.1-.25-.45-1.29.1-2.64 0 0 .84-.27 2.75 1.02.79-.22 1.65-.33 2.5-.33.85 0 1.71.11 2.5.33 1.91-1.29 2.75-1.02 2.75-1.02.55 1.35.2 2.39.1 2.64.65.71 1.03 1.6 1.03 2.71 0 3.82-2.34 4.66-4.57 4.91.36.31.69.92.69 1.85V21c0 .27.16.59.67.5C19.14 20.16 22 16.42 22 12A10 10 0 0 0 12 2z"/>
            </svg>
          </a>

          {/* Instagram */}
          <a
            href="https://instagram.com/karantly_karan"
            target="_blank"
            rel="noopener noreferrer"
            className="hover:scale-110 transition-transform"
            aria-label="Instagram"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" className="w-6 h-6 text-white/80 hover:text-white" viewBox="0 0 24 24">
              <path d="M7 2C4.243 2 2 4.243 2 7v10c0 2.757 2.243 5 5 5h10c2.757 0 5-2.243 5-5V7c0-2.757-2.243-5-5-5H7zm10 2a3 3 0 0 1 3 3v10a3 3 0 0 1-3 3H7a3 3 0 0 1-3-3V7a3 3 0 0 1 3-3h10zM12 7a5 5 0 1 0 0 10 5 5 0 0 0 0-10zm0 2a3 3 0 1 1 0 6 3 3 0 0 1 0-6zm4.5-2a1.5 1.5 0 1 0 0 3 1.5 1.5 0 0 0 0-3z"/>
            </svg>
          </a>

          {/* X / Twitter */}
          <a
            href="https://x.com/IHateCPPGUI"
            target="_blank"
            rel="noopener noreferrer"
            className="hover:scale-110 transition-transform"
            aria-label="Twitter / X"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="currentColor" className="w-6 h-6 text-white/80 hover:text-white" viewBox="0 0 24 24">
              <path d="M18.36 3H21l-6.49 7.39L22 21h-6.14l-4.82-6.41L5.5 21H3l7.01-7.98L2 3h6.3l4.53 6.1L18.36 3zm-2.18 16h1.38L7.4 5H6.02l10.16 14z"/>
            </svg>
          </a>
        </motion.div>

      </motion.div>
      <motion.div
        className="absolute bottom-8 text-white/70 text-sm tracking-wide animate-bounce"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 2, duration: 0.5 }}
      >
        Scroll Down ↓
      </motion.div>
    </section>
  );
};

export default Hero;
