import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';

// AnimatedSection with optional glowing blobs
const AnimatedSection = ({
  children,
  id,
  className = '',
  animation = 'fadeIn',
  delay = 0,
  duration = 0.5,
  threshold = 0.2,
  triggerOnce = true,
  withBlobs = false,
  withGradient = false
}) => {
  const [ref, inView] = useInView({
    threshold: threshold,
    triggerOnce: triggerOnce,
  });

  const animations = {
    fadeIn: {
      hidden: { opacity: 0 },
      visible: {
        opacity: 1,
        transition: {
          duration,
          delay,
        },
      },
    },
    slideUp: {
      hidden: { opacity: 0, y: 50 },
      visible: {
        opacity: 1,
        y: 0,
        transition: {
          duration,
          delay,
        },
      },
    },
    slideRight: {
      hidden: { opacity: 0, x: -50 },
      visible: {
        opacity: 1,
        x: 0,
        transition: {
          duration,
          delay,
        },
      },
    },
    slideLeft: {
      hidden: { opacity: 0, x: 50 },
      visible: {
        opacity: 1,
        x: 0,
        transition: {
          duration,
          delay,
        },
      },
    },
    scale: {
      hidden: { opacity: 0, scale: 0.8 },
      visible: {
        opacity: 1,
        scale: 1,
        transition: {
          duration,
          delay,
        },
      },
    },
    bounce: {
      hidden: { opacity: 0, y: 50 },
      visible: {
        opacity: 1,
        y: 0,
        transition: {
          type: 'spring',
          stiffness: 300,
          damping: 15,
          delay,
        },
      },
    },
  };

  const selectedAnimation = animations[animation] || animations.fadeIn;

  return (
    <section
      id={id}
      ref={ref}
      className={`relative overflow-hidden ${className} ${
        withGradient ? 'gradient-bg' : ''
      }`}
    >
      {withBlobs && (
        <div className="absolute inset-0 -z-10 overflow-hidden pointer-events-none">
          <div className="absolute w-96 h-96 bg-blue-500/20 rounded-full blur-3xl top-0 -left-20 animate-float" />
          <div className="absolute w-80 h-80 bg-purple-600/20 rounded-full blur-2xl bottom-0 right-0 animate-float delay-1000" />
          <div className="absolute w-72 h-72 bg-pink-500/10 rounded-full blur-2xl top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 animate-float delay-2000" />
        </div>
      )}

      <motion.div
        initial="hidden"
        animate={inView ? 'visible' : 'hidden'}
        variants={selectedAnimation}
      >
        {children}
      </motion.div>
    </section>
  );
};

export default AnimatedSection;
