import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { DarkModeToggle } from '../common/DarkModeToggle';

const Navbar = ({ activeSection, scrollToSection, darkMode, toggleDarkMode }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const navItems = ['home', 'about', 'experience', 'projects', 'skills', 'certificates', 'incoming', 'contact'];

  const handleNavigation = (sectionId) => {
    scrollToSection(sectionId);
    setIsMenuOpen(false);
  };

  return (
    <motion.nav
      className="fixed w-full backdrop-blur-md bg-white/70 dark:bg-gray-900/70 shadow-lg z-50 transition-all duration-300"
      initial={{ y: -20, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      <div className="container mx-auto px-6 py-4 flex justify-between items-center">
        {/* Logo */}
        <motion.a
          href="#home"
          className="text-3xl font-extrabold tracking-tight text-blue-600 dark:text-blue-400 glow-text"
          whileHover={{ scale: 1.1 }}
        >
          KS<span className="text-indigo-600 dark:text-indigo-400">.</span>
        </motion.a>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center space-x-6">
          {navItems.map((section) => (
            <motion.button
              key={section}
              onClick={() => handleNavigation(section)}
              className={`relative text-sm font-medium hover-underline capitalize transition-colors duration-200 ${
                activeSection === section
                  ? 'text-blue-600 dark:text-blue-400 font-semibold'
                  : 'text-gray-700 dark:text-gray-300'
              }`}
              whileHover={{ scale: 1.05 }}
            >
              {section}
            </motion.button>
          ))}

          {/* CTA */}
          <motion.a
            href="#contact"
            className="ml-4 px-4 py-2 text-sm font-semibold bg-blue-600 text-white rounded-full hover:bg-blue-700 transition"
            whileHover={{ scale: 1.05 }}
          >
            Let’s Talk
          </motion.a>
        </div>

        {/* Dark Mode Toggle */}
        <DarkModeToggle darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

        {/* Mobile Menu Toggle */}
        <button
          onClick={() => setIsMenuOpen(!isMenuOpen)}
          className="md:hidden text-gray-600 dark:text-gray-300 ml-4"
        >
          <svg
            className="w-6 h-6"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
            xmlns="http://www.w3.org/2000/svg"
          >
            {isMenuOpen ? (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            ) : (
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
            )}
          </svg>
        </button>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isMenuOpen && (
          <motion.div
            className="md:hidden bg-white/80 dark:bg-gray-900/80 border-t dark:border-gray-700 backdrop-blur-md transition-colors duration-200"
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.3 }}
          >
            {navItems.map((section) => (
              <motion.button
                key={section}
                onClick={() => handleNavigation(section)}
                className={`${
                  activeSection === section
                    ? 'bg-blue-100 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-semibold'
                    : 'text-gray-700 dark:text-gray-300'
                } w-full text-left px-6 py-3 hover:bg-blue-50 dark:hover:bg-blue-800/40 capitalize`}
                whileHover={{ x: 5 }}
              >
                {section}
              </motion.button>
            ))}
            <div className="w-full text-left px-6 py-3 flex items-center text-gray-700 dark:text-gray-300 hover:bg-blue-50 dark:hover:bg-blue-800/30 transition-colors">
              <span className="mr-2">{darkMode ? 'Light Mode' : 'Dark Mode'}</span>
              <DarkModeToggle darkMode={darkMode} toggleDarkMode={toggleDarkMode} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.nav>
  );
};

export default Navbar;
