import React, { useState, useEffect } from 'react';
import { Sun, Moon } from 'lucide-react';
import { motion } from 'framer-motion';

const DarkModeToggle = ({ darkMode, toggleDarkMode }) => {
  // Animation variants for the toggle button
  const buttonVariants = {
    light: { backgroundColor: '#f3f4f6', rotate: 0 },
    dark: { backgroundColor: '#374151', rotate: 180 }
  };

  // Icon animation variants
  const iconVariants = {
    light: { opacity: 1, y: 0 },
    dark: { opacity: 0, y: -20 }
  };

  const darkIconVariants = {
    light: { opacity: 0, y: 20 },
    dark: { opacity: 1, y: 0 }
  };

  return (
    <motion.button 
      onClick={toggleDarkMode}
      className="p-2 rounded-full relative"
      variants={buttonVariants}
      initial={darkMode ? "dark" : "light"}
      animate={darkMode ? "dark" : "light"}
      transition={{ duration: 0.3, type: "spring", stiffness: 300 }}
      aria-label={darkMode ? "Switch to light mode" : "Switch to dark mode"}
    >
      <div className="relative w-5 h-5">
        <motion.div
          className="absolute inset-0"
          variants={iconVariants}
          initial={darkMode ? "dark" : "light"}
          animate={darkMode ? "dark" : "light"}
          transition={{ duration: 0.3 }}
        >
          <Sun size={20} className="text-gray-800" />
        </motion.div>
        <motion.div
          className="absolute inset-0"
          variants={darkIconVariants}
          initial={darkMode ? "dark" : "light"}
          animate={darkMode ? "dark" : "light"}
          transition={{ duration: 0.3 }}
        >
          <Moon size={20} className="text-gray-200" />
        </motion.div>
      </div>
    </motion.button>
  );
};

// Hook to manage dark mode with auto switching based on time
const useDarkMode = () => {
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    // Check for saved theme preference or use system preference
    const savedTheme = localStorage.getItem('theme');
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    
    // Get current hour for auto dark mode
    const currentHour = new Date().getHours();
    const isNightTime = currentHour < 8 || currentHour >= 18; // Before 8 AM or after 6 PM
    
    // Decision logic for dark mode:
    // 1. If user has explicitly set a preference, use that
    // 2. If not, check if it's night time for auto dark mode
    // 3. If not night time, fall back to system preference
    if (savedTheme === 'dark') {
      setDarkMode(true);
      document.documentElement.classList.add('dark');
    } else if (savedTheme === 'light') {
      setDarkMode(false);
      document.documentElement.classList.remove('dark');
    } else if (isNightTime) {
      // Auto dark mode based on time
      setDarkMode(true);
      document.documentElement.classList.add('dark');
      // Don't save this preference as it's automatic
    } else if (prefersDark) {
      setDarkMode(true);
      document.documentElement.classList.add('dark');
    }
  }, []);

  const toggleDarkMode = () => {
    setDarkMode(prevMode => {
      const newMode = !prevMode;
      if (newMode) {
        document.documentElement.classList.add('dark');
        localStorage.setItem('theme', 'dark');
      } else {
        document.documentElement.classList.remove('dark');
        localStorage.setItem('theme', 'light');
      }
      return newMode;
    });
  };

  return [darkMode, toggleDarkMode];
};

export { DarkModeToggle, useDarkMode };