import React from 'react';
import SectionTitle from '../common/SectionTitle';
import Card from '../common/AnimatedCard';

const Projects = ({ id }) => {
  const projects = [
    {
      title: "Students of Southern Company",
      role: "President of GA Chapter",
      period: "Jan 2025 - Present",
      location: "Atlanta, GA",
      description: [
        "Lead events and initiatives that promote Diversity, Equity, and Inclusion (DE&I), safety, and productivity in the workplace.",
        "Managing an inspiring team to foster collaboration and inclusivity."
      ],
      link: null
    },
    {
      title: "MineByte (Coding for everyone)",
      role: "React Developer",
      period: "Jun 2024 - Present",
      location: "Remote",
      description: [
        "Built Minebyte, a platform offering free education and coding practice in 5+ languages, using React for a seamless UX/UI.",
        "Integrated Firestore for real-time database management and Firebase Authentication."
      ],
      link: "#"
    },
    {
      title: "Capstone Project for Data Science",
      role: "Data Scientist (HS Dataset from Kaggle)",
      period: "Aug 2024 - Present",
      location: "Remote",
      description: [
        "Preprocessed 662 records using Python and Perl, attaining data visualization with label encoding and 40% redundancy clean.",
        "Implemented data pipelines using PHP and integrated them into web-based tools for monitoring high-risk predictions.",
        "Optimized model training with Caffe, achieving 86% accuracy, 77% precision, and a 0.65 F1 score on prediction models."
      ],
      link: "#"
    }
  ];

  return (
    <section id={id} className="py-16 bg-white dark:bg-gray-800 transition-colors duration-200">
      <div className="container mx-auto px-4">
        <SectionTitle title="Projects & Leadership" />
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {projects.map((project, index) => (
            <ProjectCard key={index} project={project} />
          ))}
        </div>
      </div>
    </section>
  );
};

const ProjectCard = ({ project }) => {
  const { title, role, period, location, description, link } = project;
  
  return (
    <div className="bg-gray-50 dark:bg-gray-700 p-6 rounded-lg shadow-sm">
      <h3 className="text-xl font-semibold mb-2">{title}</h3>
      <p className="text-blue-600 dark:text-blue-400 mb-2">{role}</p>
      <p className="text-gray-600 dark:text-gray-400 mb-4">{period} | {location}</p>
      <ul className="list-disc pl-5 space-y-2 dark:text-gray-300">
        {description.map((item, index) => (
          <li key={index}>{item}</li>
        ))}
      </ul>
      {link && (
        <a href={link} className="text-blue-600 dark:text-blue-400 hover:underline mt-2 inline-block">
          Link to project
        </a>
      )}
    </div>
  );
};

export default Projects;