import React, { useState } from 'react';
import { BookOpen, Star, ChevronRight, ChevronDown } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedSection from '../common/AnimatedSection';
import SectionTitle from '../common/SectionTitle';


const AnimatedAbout = ({ id }) => {
  const [activeTab, setActiveTab] = useState('summary');
  const [expanded, setExpanded] = useState(null);

  const tabs = [
    { id: 'summary', label: 'Summary' },
    { id: 'education', label: 'Education' },
    { id: 'achievements', label: 'Achievements' },
  ];

  const achievements = [
    {
      id: 1,
      title: 'Voice Synthesis Model Improvement',
      short: 'Improved model accuracy by 30%',
      long: 'Implemented transformer fine-tuning and data optimization for natural-sounding voice generation.',
      metrics: ['+30% Accuracy', '-50% Training Time', '15% Speaker Adaptation'],
    },
    {
      id: 2,
      title: 'Award-winning ML Hackathon',
      short: 'Led a team to 1st place at GT Hack',
      long: 'Built an ML-based accessibility tool that was adopted by the campus accessibility office.',
      metrics: ['1st Place', 'Used by 50+ Users', 'Featured at Georgia Tech'],
    },
    {
      id: 3,
      title: 'IEEE Research Publication',
      short: 'Published on Neural Voice Replication',
      long: 'Introduced neural architecture improvements for voice modeling, cited 12+ times.',
      metrics: ['IEEE Conference', 'Cited 12+ times', 'Implemented by 2 labs'],
    },
  ];

  return (
    <AnimatedSection
      id={id}
      className="py-16 text-white gradient-bg"
      animation="fadeIn"
      withBlobs
      withGradient
    >

      <div className="container mx-auto px-4">
        <SectionTitle title="👨‍💻 About Me" />

        {/* Tabs */}
        <div className="flex gap-2 justify-center mb-8">
          {tabs.map((tab) => (
            <motion.button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`px-4 py-2 rounded-lg font-medium transition-all ${
                activeTab === tab.id
                  ? 'bg-blue-600 text-white shadow-lg'
                  : 'bg-gray-800 hover:bg-gray-700 text-gray-300'
              }`}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.97 }}
            >
              {tab.label}
            </motion.button>
          ))}
        </div>

        {/* Tab content */}
        <AnimatePresence mode="wait">
          {activeTab === 'summary' && (
              <motion.div
              key="summary"
              className="max-w-3xl mx-auto bg-[#161a20] rounded-xl p-8 shadow-xl text-lg leading-relaxed"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.5 }}
            >
              <motion.h3
                className="text-2xl font-bold text-blue-400 mb-4 glow-text"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2 }}
              >
                Building with Purpose ⚙️
              </motion.h3>
            
              <p className="mb-4">
                <strong className="text-blue-400">Hi, I’m Karan.</strong> I’m a <span className="text-yellow-400 font-semibold">Machine Learning Engineer</span> and <span className="text-pink-400 font-semibold">Full-Stack Developer</span> based in Atlanta.
              </p>
              <p className="mb-6">
                From deploying ML models on Azure to building fast UIs, I’ve worked across the stack. I’m currently pursuing my Master’s at <span className="text-green-400 font-semibold">Georgia Tech</span> — and I love crafting intelligent, efficient systems.
              </p>
            
              {/* Badges */}
              <div className="flex flex-wrap gap-3 mt-4">
                <span className="px-3 py-1 bg-blue-800 text-blue-200 text-sm rounded-full">AI/ML</span>
                <span className="px-3 py-1 bg-indigo-800 text-indigo-200 text-sm rounded-full">Cloud Architect</span>
                <span className="px-3 py-1 bg-green-800 text-green-200 text-sm rounded-full">CS @ GT</span>
                <span className="px-3 py-1 bg-yellow-700 text-yellow-200 text-sm rounded-full">Leadership</span>
              </div>
            </motion.div>
          
          )}

          {activeTab === 'education' && (
            <motion.div
              key="education"
              className="grid md:grid-cols-2 gap-6 max-w-4xl mx-auto"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.5 }}
            >
              <div className="bg-[#161a20] rounded-lg p-6 shadow-lg">
                <div className="flex items-center mb-2 text-blue-400">
                  <BookOpen size={20} className="mr-2" />
                  <h4 className="text-lg font-semibold">Georgia Tech</h4>
                </div>
                <p className="text-gray-300">Master’s in Computer Science</p>
                <p className="text-sm text-gray-400 mb-2">GPA: 4.0 | AI, NLP, Deep Learning</p>
                <ul className="list-disc ml-5 text-sm text-gray-300 space-y-1">
                  <li>Advanced Machine Learning Systems</li>
                  <li>Deep Learning for Perception</li>
                  <li>Natural Language Processing</li>
                </ul>
              </div>

              <div className="bg-[#161a20] rounded-lg p-6 shadow-lg">
                <div className="flex items-center mb-2 text-blue-400">
                  <BookOpen size={20} className="mr-2" />
                  <h4 className="text-lg font-semibold">Georgia State University</h4>
                </div>
                <p className="text-gray-300">Bachelor’s in Computer Science</p>
                <p className="text-sm text-gray-400 mb-2">GPA: 3.72 | iOS Dev, Algo Design</p>
                <ul className="list-disc ml-5 text-sm text-gray-300 space-y-1">
                  <li>Dean's List (6 semesters)</li>
                  <li>VP, CS Student Association</li>
                  <li>Research Assistant</li>
                </ul>
              </div>
            </motion.div>
          )}

          {activeTab === 'achievements' && (
            <motion.div
              key="achievements"
              className="grid md:grid-cols-2 gap-6 max-w-4xl mx-auto"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.5 }}
            >
              {achievements.map((a) => (
                <motion.div
                  key={a.id}
                  className="bg-[#161a20] rounded-lg p-6 shadow-lg"
                  whileHover={{ scale: 1.02 }}
                >
                  <div
                    className="flex justify-between items-center cursor-pointer"
                    onClick={() => setExpanded(expanded === a.id ? null : a.id)}
                  >
                    <h4 className="text-lg font-semibold text-blue-400 flex items-center">
                      <Star size={18} className="mr-2 text-yellow-400" />
                      {a.title}
                    </h4>
                    {expanded === a.id ? (
                      <ChevronDown className="text-gray-400" size={18} />
                    ) : (
                      <ChevronRight className="text-gray-400" size={18} />
                    )}
                  </div>
                  <p className="text-sm text-gray-300 mt-1">{a.short}</p>

                  <AnimatePresence>
                    {expanded === a.id && (
                      <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        exit={{ height: 0, opacity: 0 }}
                        transition={{ duration: 0.3 }}
                        className="mt-3 pt-3 border-t border-gray-700"
                      >
                        <p className="text-sm text-gray-400 mb-2">{a.long}</p>
                        <div className="flex flex-wrap gap-2">
                          {a.metrics.map((m, i) => (
                            <span
                              key={i}
                              className="bg-blue-900 text-blue-300 px-3 py-1 rounded-full text-xs font-medium"
                            >
                              {m}
                            </span>
                          ))}
                        </div>
                      </motion.div>
                    )}
                  </AnimatePresence>
                </motion.div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </AnimatedSection>
  );
};

export default AnimatedAbout;
