import React from 'react';
import './App.css';

// Layout Components
import Navbar from './components/layout/Navbar';
import Footer from './components/layout/Footer';
import ScrollProgressBar from './components/common/ScrollProgressBar';
// import FigmaCursor from './components/common/FigmaCursor'; Also place <FigmaCursor /> in the return statement of App.js after ScrollProgressBar
import { useDarkMode } from './components/common/DarkModeToggle';

// Animated Section Components
import Hero from './components/sections/AnimatedHero';
import About from './components/sections/AnimatedAbout';
import Experience from './components/sections/AnimatedExperience';
import Projects from './components/sections/Projects';
import Skills from './components/sections/AnimatedSkills';
import Certificates from './components/sections/Certificates';
import Incoming from './components/sections/Incoming';
import Contact from './components/sections/Contact';

const App = () => {
  const [activeSection, setActiveSection] = React.useState('home');
  const [darkMode, toggleDarkMode] = useDarkMode();

  const scrollToSection = (sectionId) => {
    setActiveSection(sectionId);
    document.getElementById(sectionId).scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className={`min-h-screen ${darkMode ? 'dark' : ''} bg-gray-50 dark:bg-gray-900 text-gray-800 dark:text-gray-200 font-sans transition-colors duration-200`}>
      <ScrollProgressBar />

      
      <Navbar 
        activeSection={activeSection} 
        scrollToSection={scrollToSection} 
        darkMode={darkMode} 
        toggleDarkMode={toggleDarkMode} 
      />
      
      <Hero id="home" />
      <About id="about" />
      <Experience id="experience" className="section-experience" />
      <Projects id="projects" className="section-projects" />
      <Skills id="skills" className="section-skills" />
      <Certificates id="certificates" className="section-certificates" />
      <Incoming id="incoming" className="section-incoming" />
      <Contact id="contact" className="section-contact" />
      
      <Footer />
    </div>
  );
};

export default App;