import React from 'react';
import { MapPin } from 'lucide-react';
import { motion } from 'framer-motion';
import SectionTitle from '../common/SectionTitle';
import AnimatedSection from '../common/AnimatedSection';
import AnimatedCard from '../common/AnimatedCard';

const Experience = ({ id }) => {
  const experiences = [
    {
      title: "Innovation Intern (Azure DevOps and Model Training)",
      company: "Southern Company",
      location: "Atlanta, GA",
      period: "Jan 2025 - Present",
      responsibilities: [
        "Collaborated with a team on AI projects using Python, Pytorch, and Whisper to synthesize and replicate a custom trained voice.",
        "Prototyped a Speech-to-text app with OpenAI's Whisper Model running on GPU CUDA for seamless IoT system integration.",
        "Worked with XTTS-v2 for real-time voice synthetization and replication, in accordance with Software Development Life Cycle.",
        "Deployed AI models and websites on Azure app services with Node.JS and Python runtimes to ensure a wide range availability.",
        "Currently working in CoPilot Studio developing agents with the help of AI builder and Power Automate in Azure Workspace."
      ]
    },
    {
      title: "Software Engineering Coach",
      company: "thecoderschool",
      location: "Suwanee, GA",
      period: "Jul 2024 - Dec 2024",
      responsibilities: [
        "Processed 5,000+ rows of data using Pandas to optimize model training datasets for projects in Google Teachable Machine.",
        "Introduced PyTorch and TensorFlow exercises, improving AI skills among 50+ students with an 80% satisfaction rate.",
        "Led workshops on end-to-end firmware design and development, aligning projects with industry standards and compliance.",
        "Configured AVM instances in our web services workshop using Linux commands running 10% more efficiently than Windows."
      ]
    },
    {
      title: "Machine Learning Intern (NLP for speech refinement)",
      company: "Nexcen Global Inc.",
      location: "Cumming, GA",
      period: "Jan 2023 - May 2023",
      responsibilities: [
        "Leveraged Natural Language Processing (NLP) ML models with gTTS to enhance and refine input, boosting accuracy by 20%.",
        "Integrated models like BERT, Whisper, and GPT, achieving a 15% improvement in speech-to-text accuracy across voice data.",
        "Designed a data pipeline on cloud to process 1TB+ of input voice data monthly, utilizing Big Data for training and analysis."
      ]
    },
    {
      title: "Cloud Solutions Associate (Hosted SharePoint on AWS)",
      company: "Nexcen Global Inc.",
      location: "Cumming, GA",
      period: "Jun 2022 - Dec 2022",
      responsibilities: [
        "Optimized cloud server efficiency by 30% through resource management and performance optimization using CloudTrail.",
        "Configured Autoscaling EC2 Instances, with CloudFormation, supporting 10,000+ users with on-demand resource allocation.",
        "Boosted server responsiveness and performance by 17% via CloudTrail and CloudWatch, cutting response times by 10%.",
        "Improved accessibility for 50+ employees by hosting SharePoint on AWS using Lambda for data analysis and automation."
      ]
    }
  ];

  // Animation for staggered list items
  const listVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, x: -10 },
    visible: { opacity: 1, x: 0 }
  };

  return (
    <AnimatedSection
      id={id}
      className="py-16 bg-gray-50 dark:bg-gray-900 transition-colors duration-200"
      animation="fadeIn"
    >
      <div className="container mx-auto px-4">
        <SectionTitle title="Work Experience" />
        <div className="space-y-8">
          {experiences.map((exp, index) => (
            <AnimatedCard key={index} delay={0.2 + (index * 0.1)}>
              <div className="flex flex-wrap justify-between items-start mb-4">
                <div>
                  <h3 className="text-xl font-semibold">{exp.title}</h3>
                  <p className="text-blue-600 dark:text-blue-400">{exp.company}</p>
                </div>
                <div className="mt-2 md:mt-0 flex items-center">
                  <MapPin size={16} className="text-gray-600 dark:text-gray-400 mr-1" />
                  <span className="text-gray-600 dark:text-gray-400 mr-4">{exp.location}</span>
                  <span className="text-gray-600 dark:text-gray-400">{exp.period}</span>
                </div>
              </div>
              <motion.ul
                className="list-disc pl-5 space-y-2 dark:text-gray-300"
                variants={listVariants}
                initial="hidden"
                animate="visible"
              >
                {exp.responsibilities.map((responsibility, idx) => (
                  <motion.li key={idx} variants={itemVariants}>
                    {responsibility}
                  </motion.li>
                ))}
              </motion.ul>
            </AnimatedCard>
          ))}
        </div>
      </div>
    </AnimatedSection>
  );
};

export default Experience;